sql:
SELECT brand_name
FROM brands
WHERE brand_id = 1;

SELECT COUNT(customers.customer_id) AS number_of_customers, COUNT(orders.order_id) AS number_of_orders
FROM customers
LEFT JOIN orders ON customers.customer_id = orders.customer_id;

SELECT COUNT(*) 
FROM brands 
WHERE brand_country = 'USA';

SELECT COUNT(recommendation_id) AS total_recommendations
FROM size_recommendations
WHERE product_id = 1;

SELECT brand_name, brand_description
FROM brands
ORDER BY brand_founding_year ASC;

external_knowledge:
- 'young upstarts' refers to brands founded after the year 2000;
- 'sprouted since the dawn of the new millennium' means brands founded after 2000;
- 'ventured forth with their creations' is a metaphor for having product lines;
- 'blossoms' is used metaphorically to describe product lines;
- 'new trees' symbolize the brands that are relatively new.

sql:
SELECT brand_name, brand_website, COUNT(*) AS number_of_brands
FROM brands
GROUP BY brand_name, brand_website;
